marks = 85

# Using if, elif, and else for branching logic
if marks >= 90:
    print("Grade: A+")
elif marks >= 80:
    print("Grade: A")
elif marks >= 70:
    print("Grade: B")
else:
    print("Grade: C")

# Nested If
# You can have an if statement inside another if statement
age = 20
has_ticket = True

if age >= 18:
    if has_ticket:
        print("You can enter the theater.")
    else:
        print("You need a ticket to enter.")
else:
    print("You are too young for this movie.")

# Using break
for i in range(1, 10):
    if i == 5:
        break
    print(i, end=" ")
# Output: 1 2 3 4
print() # Newline

# Using continue
for i in range(1, 6):
    if i == 3:
        continue
    print(i, end=" ")
# Output: 1 2 4 5

# Using pass
if True:
    pass # I will write code here later, but I don't want a syntax error now

target = 7
# Searching for a number
for i in range(5):
    if i == target:
        print("Found it!")
        break
else:
    # This runs because the loop finished all iterations and 'break' was never hit
    print("Target not found in the range.")

